const msg = $json.message ?? {};
const caption = (msg.caption || '').trim();
const lines = caption.split(/\r?\n/).map((x) => x.trim()).filter(Boolean);
const title = lines[0] || (msg.document?.file_name || `Movie #${msg.message_id || Date.now()}`);
const description = lines.slice(1).join('\n');
const sourceChannel = ($env.TELEGRAM_SOURCE_CHANNEL_USERNAME || '').trim();
const messageId = msg.message_id;
const fileId = msg.document?.file_id || msg.video?.file_id || msg.audio?.file_id || '';
let sourceLink = '';
if (sourceChannel && messageId) {
  sourceLink = `https://t.me/${sourceChannel}/${messageId}`;
}
return [{
  title,
  description,
  messageId,
  fileId,
  sourceLink,
  rawMessage: msg
}];

const input = $input.first().json;
const snoteLink = input.url || input.link || input.data?.url || input.data?.link || input.postUrl || '';
if (!snoteLink) {
  throw new Error('Snote API chưa trả về link bài viết (url/link).');
}

const timeout = Number($env.SHORTENER_TIMEOUT_MS || 15000);
const endpoint = ($env.SHORTENER_API_URL || '').trim();
const apiKey = ($env.SHORTENER_API_KEY || '').trim();

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

async function shortenOnce(index) {
  if (!endpoint) {
    return snoteLink;
  }

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: endpoint,
      timeout,
      headers: {
        Authorization: apiKey ? `Bearer ${apiKey}` : undefined,
        'Content-Type': 'application/json'
      },
      body: { longUrl: snoteLink },
      json: true
    });

    return response.shortUrl || response.short_url || response.link || response.url || snoteLink;
  } catch (error) {
    return snoteLink;
  }
}

const links = [];
for (let i = 1; i <= 3; i += 1) {
  links.push(await shortenOnce.call(this, i));
  if (i < 3) await sleep(1200);
}

return [{
  ...$json,
  snoteLink,
  shortLinks: links
}];

const data = $json;
const links = data.shortLinks || [];
const l1 = links[0] || data.snoteLink;
const l2 = links[1] || data.snoteLink;
const l3 = links[2] || data.snoteLink;

const body = [
  `*${data.title || 'Movie mới'}*`,
  data.description || '',
  '',
  `[Link 1](${l1})`,
  `[Link 2](${l2})`,
  `[Link 3](${l3})`
].filter(Boolean).join('\n');

return [{
  ...data,
  publishText: body,
  discordText: body.replace(/\*/g, '**')
}];
